def solve(equations, values, queries):
    import collections
    graph = collections.defaultdict(dict)
    for (u, v), val in zip(equations, values):
        graph[u][v] = val
        graph[v][u] = 1.0 / val

    def dfs(src, dst, visited):
        if src not in graph or dst not in graph:
            return -1.0
        if src == dst:
            return 1.0
        visited.add(src)
        for neighbor, weight in graph[src].items():
            if neighbor not in visited:
                res = dfs(neighbor, dst, visited)
                if res != -1.0:
                    return weight * res
        return -1.0

    res = []
    for u, v in queries:
        res.append(float(dfs(u, v, set())))
    return ' '.join(f"{x:.5f}" for x in res)

